import{_ as r,o as i,c as a,ak as s,au as t}from"./chunks/framework.CRYrbBns.js";const b=JSON.parse('{"title":"USB-IP, Partage de ports série sur réseau","description":"","frontmatter":{},"headers":[],"relativePath":"15 - USB-IP.md","filePath":"15 - USB-IP.md"}'),o={name:"15 - USB-IP.md"};function l(u,e,n,d,p,c){return i(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="usb-ip-partage-de-ports-serie-sur-reseau" tabindex="-1">USB-IP, Partage de ports série sur réseau <a class="header-anchor" href="#usb-ip-partage-de-ports-serie-sur-reseau" aria-label="Permalink to “USB-IP, Partage de ports série sur réseau”">​</a></h1><blockquote><p>Nous avons besoin d&#39;un logiciel nous permettant d&#39;avoir un <strong>serveur de calcul relativement puissant</strong> ( exécutant le modèle IA ou la téléoperation ) et d&#39;un <strong>serveur opérant le bras robotique</strong> sur la plateforme, ici un Raspberry pi (pas suffisamment puissant pour exécuter le modèle IA).</p></blockquote><p><img src="'+t+'" alt=""></p><p>Cette méthode permet de faire croire au serveur calcul qu’il communique avec un port série local (<code>COMx</code> sous Windows), alors qu’il communique en réalité avec le port série du serveur opérateur.</p><blockquote><p>Pour cela, nous allons utiliser l&#39;outil &quot;usbip&quot;. Permettant au deux machines d&#39;échanger leurs ports série sur un même réseau.</p></blockquote><h1 id="installation-sur-le-serveur-operateur-linux" tabindex="-1">Installation sur le serveur opérateur (linux) <a class="header-anchor" href="#installation-sur-le-serveur-operateur-linux" aria-label="Permalink to “Installation sur le serveur opérateur (linux)”">​</a></h1><hr><ol><li>Installer <strong>usbIP</strong> : <code>sudo apt install usbip</code></li><li>Charger les modules noyaux nécessaires : <code>sudo modprobe usbip_core</code></li><li><code>sudo modprobe usbip_host</code></li><li><code>sudo modprobe vhci-hcd</code></li><li>Identifier le périphérique USB série : <code>lsusb</code><ol><li>Vous devrez voir apparaitre de nombreux ports série, dont : &quot;/dev/ttyACMx&quot;</li><li>Pour s&#39;assurer que ce périphérique est bien celui que vous utiliser, vous pouvez le débrancher, et relancer la commande. Il devrait disparaitre.</li></ol></li><li>Démarrer le service : <code>usbip : sudo usbip -D</code></li><li>Lister les périphériques disponibles : <code>usbip list -l</code><ol><li>Cette commande fait également apparaitre le &quot;busid&quot; correspondant à votre périphérique. (ex : 1-1.4)</li></ol></li><li>Partager le périphérique : <code>sudo usbip bind -b BUS_ID</code></li><li>Votre périphérique est maintenant partagé !</li></ol><h1 id="installation-sur-le-serveur-calcul-widows" tabindex="-1">Installation sur le serveur calcul (Widows) <a class="header-anchor" href="#installation-sur-le-serveur-calcul-widows" aria-label="Permalink to “Installation sur le serveur calcul (Widows)”">​</a></h1><hr><ol><li>Installer la dernière version de <a href="https://github.com/vadimgrn/usbip-win2" target="_blank" rel="noreferrer">usbip-win2</a> usbip-win2 sur <a href="https://github.com/vadimgrn/usbip-win2/releases" target="_blank" rel="noreferrer">Github</a></li><li>Une fois l&#39;installation terminé, il est normalement demandé de redémarrer votre ordinateur.</li><li>Vous pouvez ensuite vous rendre dans le réertoire d&#39;installation de usbip, normalement dans : &quot;C:\\Program Files\\USBip&quot; avec la commande : <code>cd C:\\Program Files\\USBip</code></li><li>Vous pouvez vérifier que le serveur opérateur partage bien son port série avec la commande : <code>usbip.exe list -r IP_RASPBERRY</code></li><li>Vous attacher au périphérique du serveur : <code>usbip.exe -r IP_RASPBERRY -b BUS_ID</code></li><li>Si la commande s&#39;est exécuté avec succès, vous devriez voir apparaitre un nouveau périphérique COM dans votre gestionnaire de périphériques.</li></ol><h1 id="erreurs-rencontres" tabindex="-1">Erreurs rencontrés <a class="header-anchor" href="#erreurs-rencontres" aria-label="Permalink to “Erreurs rencontrés”">​</a></h1><table tabindex="0"><thead><tr><th>Problème</th><th>Solution</th></tr></thead><tbody><tr><td>Erreur &quot;Multiple instances of VHCI device interface found&quot;</td><td>Désinstallez toutes les instances de VHCI via le Gestionnaire de périphériques et <code>pnputil</code>.</td></tr></tbody></table>',13)])])}const h=r(o,[["render",l]]);export{b as __pageData,h as default};
